1	/**
2	 * The Laboratory's phase orchestrator engines.
3	 *
4	 * The post-and-collect-default rig template enumerates five phases as
5	 * a backbone (setup → scenario → probes → archive → teardown), one
6	 * engine per phase. Each phase engine is a clockwork orchestrator: it
7	 * reads `writ.ext.laboratory.config`, computes the per-phase graft,
8	 * and returns immediately with `{ status: 'completed', graft, ...}`.
9	 * The grafted engines do the real work; phase orchestrators are
10	 * organizational.
11	 *
12	 * Phase orchestrators do not isolate data — all grafted engines
13	 * share a single namespace, so cross-phase upstream refs work
14	 * naturally. Engine ids follow stable naming conventions
15	 * (`fixture-<id>-setup`, `scenario`, `probe-<id>`, `archive`,
16	 * `fixture-<id>-teardown`); each phase derives the ids it needs
17	 * from the trial config without going through prior phases' yields.
18	 *
19	 * Why staged phases instead of one god orchestrator:
20	 *
21	 *   - Template documents the trial flow as the user-facing shape
22	 *     (the template is no longer a one-engine no-op).
23	 *   - Per-phase failure visibility: oculus shows
24	 *     `lab.probes-phase` failed, not "the orchestrator failed
25	 *     somewhere".
26	 *   - Each phase has cohesive logic (DAG sort, parallel scatter,
27	 *     reverse-sequential chain) — splitting them avoids one big
28	 *     function with phase-mode flags.
29	 *   - Sets up the extension point: a future plugin contributing a
30	 *     `lab.warmup-phase` slots into a custom template alongside
31	 *     existing phases without forking a god engine.
32	 *
33	 * graftTail is set only on `lab.teardown-phase` (the rig's true end
34	 * for completion gating). Intermediate phase orchestrators omit
35	 * graftTail so each next phase fires immediately when the prior
36	 * orchestrator returns — real work-engines wait via their explicit
37	 * upstream refs, not graftTail propagation.
38	 */
39	
40	import type { EngineDesign, EngineRunResult } from '@shardworks/fabricator-apparatus';
41	import type { WritDoc } from '@shardworks/clerk-apparatus';
42	import type { RigTemplateEngine, SpiderEngineRunResult } from '@shardworks/spider-apparatus';
43	import type { LaboratoryTrialConfig, TrialFixtureDecl } from '../types.ts';
44	
45	// ── Shared helpers ─────────────────────────────────────────────────
46	
47	/**
48	 * Stable engine-id naming conventions. Every phase derives the ids
49	 * it needs from the trial config using these helpers — no
50	 * cross-phase data flow is required for naming.
51	 */
52	export const SETUP_ID = (fixtureId: string): string => `fixture-${fixtureId}-setup`;
53	export const TEARDOWN_ID = (fixtureId: string): string => `fixture-${fixtureId}-teardown`;
54	export const SCENARIO_ID = 'scenario';
55	export const PROBE_ID = (probeId: string): string => `probe-${probeId}`;
56	export const ARCHIVE_ID = 'archive';
57	
58	/**
59	 * Convention: derive a fixture's teardown engine id from its setup
60	 * engine id when no explicit override is provided. Replaces a
61	 * trailing `-setup` with `-teardown`. If the setup id does not end
62	 * in `-setup`, appends `-teardown`.
63	 */
64	export function deriveTeardownEngineId(fixture: TrialFixtureDecl): string {
65	  if (fixture.teardownEngineId !== undefined) return fixture.teardownEngineId;
66	  if (fixture.engineId.endsWith('-setup')) {
67	    return fixture.engineId.replace(/-setup$/, '-teardown');
68	  }
69	  return `${fixture.engineId}-teardown`;
70	}
71	
72	/**
73	 * Topologically sort fixtures by dependsOn. Every fixture appears
74	 * after all of its dependencies. Stable: among fixtures whose
75	 * dependencies are all already placed, declaration order is
76	 * preserved.
77	 *
78	 * Throws on cycles, unknown dependsOn references, or duplicate ids.
79	 */
80	export function topoSortFixtures(fixtures: TrialFixtureDecl[]): TrialFixtureDecl[] {
81	  const byId = new Map<string, TrialFixtureDecl>();
82	  for (const fixture of fixtures) {
83	    if (byId.has(fixture.id)) {
84	      throw new Error(`[lab] duplicate fixture id: "${fixture.id}"`);
85	    }
86	    byId.set(fixture.id, fixture);
87	  }
88	
89	  for (const fixture of fixtures) {
90	    for (const dep of fixture.dependsOn ?? []) {
91	      if (!byId.has(dep)) {
92	        throw new Error(
93	          `[lab] fixture "${fixture.id}" dependsOn unknown fixture "${dep}"`,
94	        );
95	      }
96	    }
97	  }
98	
99	  const result: TrialFixtureDecl[] = [];
100	  const placed = new Set<string>();
101	  const remaining = [...fixtures];
102	
103	  while (remaining.length > 0) {
104	    const before = remaining.length;
105	    for (let i = 0; i < remaining.length; i += 1) {
106	      const fixture = remaining[i]!;
107	      const deps = fixture.dependsOn ?? [];
108	      if (deps.every((d) => placed.has(d))) {
109	        result.push(fixture);
110	        placed.add(fixture.id);
111	        remaining.splice(i, 1);
112	        i -= 1;
113	      }
114	    }
115	    if (remaining.length === before) {
116	      const ids = remaining.map((f) => f.id).join(', ');
117	      throw new Error(`[lab] fixture dependsOn cycle among: ${ids}`);
118	    }
119	  }
120	
121	  return result;
122	}
123	
124	/**
125	 * Read and validate the trial config from a writ. All phase
126	 * orchestrators share this entry path — fail-loud on missing
127	 * config so the manifest CLI's validation contract is the only
128	 * gate.
129	 */
130	function readTrialConfig(givens: Record<string, unknown>, phaseEngineId: string): {
131	  writ: WritDoc;
132	  config: LaboratoryTrialConfig;
133	} {
134	  const writ = givens.writ as WritDoc | undefined;
135	  if (!writ) {
136	    throw new Error(
137	      `[${phaseEngineId}] missing required given "writ" — the rig template must pass \${writ}.`,
138	    );
139	  }
140	  const config = (writ.ext as { laboratory?: { config?: LaboratoryTrialConfig } } | undefined)
141	    ?.laboratory?.config;
142	  if (!config) {
143	    throw new Error(
144	      `[${phaseEngineId}] trial writ ${writ.id} missing ext.laboratory.config — manifest CLI should reject this at post time.`,
145	    );
146	  }
147	  return { writ, config };
148	}
149	
150	// ── Per-phase graft builders (pure; tested directly) ───────────────
151	
152	/**
153	 * Build the setup phase's graft: one engine per fixture, in topo
154	 * order. A fixture's setup engine upstreams its dependsOn fixtures'
155	 * setup engines (or the head — `headEngineId` — when it has no
156	 * deps).
157	 */
158	export function buildSetupGraft(
159	  config: LaboratoryTrialConfig,
160	  headEngineId: string,
161	): { graft: RigTemplateEngine[]; ordered: TrialFixtureDecl[] } {
162	  const ordered = topoSortFixtures(config.fixtures);
163	  const graft: RigTemplateEngine[] = [];
164	  for (const fixture of ordered) {
165	    const deps = fixture.dependsOn ?? [];
166	    const upstream = deps.length > 0 ? deps.map(SETUP_ID) : [headEngineId];
167	    graft.push({
168	      id: SETUP_ID(fixture.id),
169	      designId: fixture.engineId,
170	      upstream,
171	      givens: fixture.givens,
172	    });
173	  }
174	  return { graft, ordered };
175	}
176	
177	/**
178	 * Build the scenario phase's graft: one engine for the scenario.
179	 * Upstreams every fixture's setup engine, so it waits for the full
180	 * setup wave to complete. When there are no fixtures, upstreams
181	 * the head (the scenario phase orchestrator's own id).
182	 */
183	export function buildScenarioGraft(
184	  config: LaboratoryTrialConfig,
185	  headEngineId: string,
186	): RigTemplateEngine[] {
187	  const upstream =
188	    config.fixtures.length > 0
189	      ? topoSortFixtures(config.fixtures).map((f) => SETUP_ID(f.id))
190	      : [headEngineId];
191	  return [
192	    {
193	      id: SCENARIO_ID,
194	      designId: config.scenario.engineId,
195	      upstream,
196	      givens: config.scenario.givens,
197	    },
198	  ];
199	}
200	
201	/**
202	 * Build the probes phase's graft: one engine per probe. Each probe
203	 * upstreams the scenario engine; probes themselves run in parallel.
204	 */
205	export function buildProbesGraft(
206	  config: LaboratoryTrialConfig,
207	): RigTemplateEngine[] {
208	  return config.probes.map((probe) => ({
209	    id: PROBE_ID(probe.id),
210	    designId: probe.engineId,
211	    upstream: [SCENARIO_ID],
212	    givens: probe.givens,
213	  }));
214	}
215	
216	/**
217	 * Build the archive phase's graft: one archive engine. Upstreams
218	 * every probe engine; or the scenario engine when there are no
219	 * probes.
220	 */
221	export function buildArchiveGraft(
222	  config: LaboratoryTrialConfig,
223	): RigTemplateEngine[] {
224	  const upstream =
225	    config.probes.length > 0
226	      ? config.probes.map((p) => PROBE_ID(p.id))
227	      : [SCENARIO_ID];
228	  return [
229	    {
230	      id: ARCHIVE_ID,
231	      designId: config.archive.engineId,
232	      upstream,
233	      givens: config.archive.givens,
234	    },
235	  ];
236	}
237	
238	/**
239	 * Build the teardown phase's graft: one engine per fixture, REVERSE
240	 * topo order, sequential chain rooted at archive. Sequential (not
241	 * parallel) so a teardown failure stops the chain rather than
242	 * shredding sibling teardowns concurrently.
243	 *
244	 * Returns the graft and the tail engine id (the rig's true end —
245	 * teardown phase sets graftTail to this for completion gating).
246	 */
247	export function buildTeardownGraft(
248	  config: LaboratoryTrialConfig,
249	): { graft: RigTemplateEngine[]; tail: string } {
250	  const ordered = topoSortFixtures(config.fixtures);
251	  const graft: RigTemplateEngine[] = [];
252	  let prevTail: string = ARCHIVE_ID;
253	  for (let i = ordered.length - 1; i >= 0; i -= 1) {
254	    const fixture = ordered[i]!;
255	    const id = TEARDOWN_ID(fixture.id);
256	    graft.push({
257	      id,
258	      designId: deriveTeardownEngineId(fixture),
259	      upstream: [prevTail],
260	      givens: fixture.givens,
261	    });
262	    prevTail = id;
263	  }
264	  return { graft, tail: prevTail };
265	}
266	
267	// ── Phase orchestrator engines ─────────────────────────────────────
268	
269	const setupPhaseEngine: EngineDesign = {
270	  id: 'lab.setup-phase',
271	  async run(givens, context): Promise<EngineRunResult> {
272	    const { config } = readTrialConfig(givens, 'lab.setup-phase');
273	    const { graft, ordered } = buildSetupGraft(config, context.engineId);
274	    const result: SpiderEngineRunResult = {
275	      status: 'completed',
276	      yields: {
277	        fixtureCount: ordered.length,
278	        fixtureIds: ordered.map((f) => f.id),
279	      },
280	      graft,
281	      // graftTail intentionally unset: the scenario engine has
282	      //   explicit upstream refs into each fixture-setup, so the
283	      //   scenario phase can fire immediately upon this engine's
284	      //   return without waiting for fixtures to complete first.
285	    };
286	    return result as EngineRunResult;
287	  },
288	};
289	
290	const scenarioPhaseEngine: EngineDesign = {
291	  id: 'lab.scenario-phase',
292	  async run(givens, context): Promise<EngineRunResult> {
293	    const { config } = readTrialConfig(givens, 'lab.scenario-phase');
294	    const graft = buildScenarioGraft(config, context.engineId);
295	    const result: SpiderEngineRunResult = {
296	      status: 'completed',
297	      yields: { scenarioEngine: config.scenario.engineId },
298	      graft,
299	    };
300	    return result as EngineRunResult;
301	  },
302	};
303	
304	const probesPhaseEngine: EngineDesign = {
305	  id: 'lab.probes-phase',
306	  async run(givens): Promise<EngineRunResult> {
307	    const { config } = readTrialConfig(givens, 'lab.probes-phase');
308	    const graft = buildProbesGraft(config);
309	    const result: SpiderEngineRunResult = {
310	      status: 'completed',
311	      yields: {
312	        probeCount: config.probes.length,
313	        probeIds: config.probes.map((p) => p.id),
314	      },
315	      graft,
316	    };
317	    return result as EngineRunResult;
318	  },
319	};
320	
321	const archivePhaseEngine: EngineDesign = {
322	  id: 'lab.archive-phase',
323	  async run(givens): Promise<EngineRunResult> {
324	    const { config } = readTrialConfig(givens, 'lab.archive-phase');
325	    const graft = buildArchiveGraft(config);
326	    const result: SpiderEngineRunResult = {
327	      status: 'completed',
328	      yields: { archiveEngine: config.archive.engineId },
329	      graft,
330	    };
331	    return result as EngineRunResult;
332	  },
333	};
334	
335	const teardownPhaseEngine: EngineDesign = {
336	  id: 'lab.teardown-phase',
337	  async run(givens): Promise<EngineRunResult> {
338	    const { config } = readTrialConfig(givens, 'lab.teardown-phase');
339	    const { graft, tail } = buildTeardownGraft(config);
340	    const result: SpiderEngineRunResult = {
341	      status: 'completed',
342	      yields: { teardownCount: config.fixtures.length },
343	      graft,
344	      // graftTail set: this is the rig's true end. Spider waits
345	      //   for `tail` to complete before considering the rig done.
346	      //   When there are no fixtures, tail equals ARCHIVE_ID — the
347	      //   archive engine is the last real work in that case.
348	      graftTail: tail,
349	    };
350	    return result as EngineRunResult;
351	  },
352	};
353	
354	export const phaseEngines = {
355	  'lab.setup-phase': setupPhaseEngine,
356	  'lab.scenario-phase': scenarioPhaseEngine,
357	  'lab.probes-phase': probesPhaseEngine,
358	  'lab.archive-phase': archivePhaseEngine,
359	  'lab.teardown-phase': teardownPhaseEngine,
360	} as const;
361

