/**
 * The Laboratory's phase orchestrator engines.
 *
 * The post-and-collect-default rig template enumerates five phases as
 * a backbone (setup → scenario → probes → archive → teardown), one
 * engine per phase. Each phase engine is a clockwork orchestrator: it
 * reads `writ.ext.laboratory.config`, computes the per-phase graft,
 * and returns immediately with `{ status: 'completed', graft, ...}`.
 * The grafted engines do the real work; phase orchestrators are
 * organizational.
 *
 * Phase orchestrators do not isolate data — all grafted engines
 * share a single namespace, so cross-phase upstream refs work
 * naturally. Engine ids follow stable naming conventions
 * (`fixture-<id>-setup`, `scenario`, `probe-<id>`, `archive`,
 * `fixture-<id>-teardown`); each phase derives the ids it needs
 * from the trial config without going through prior phases' yields.
 *
 * Why staged phases instead of one god orchestrator:
 *
 *   - Template documents the trial flow as the user-facing shape
 *     (the template is no longer a one-engine no-op).
 *   - Per-phase failure visibility: oculus shows
 *     `lab.probes-phase` failed, not "the orchestrator failed
 *     somewhere".
 *   - Each phase has cohesive logic (DAG sort, parallel scatter,
 *     reverse-sequential chain) — splitting them avoids one big
 *     function with phase-mode flags.
 *   - Sets up the extension point: a future plugin contributing a
 *     `lab.warmup-phase` slots into a custom template alongside
 *     existing phases without forking a god engine.
 *
 * graftTail is set only on `lab.teardown-phase` (the rig's true end
 * for completion gating). Intermediate phase orchestrators omit
 * graftTail so each next phase fires immediately when the prior
 * orchestrator returns — real work-engines wait via their explicit
 * upstream refs, not graftTail propagation.
 */

import type { EngineDesign, EngineRunResult } from '@shardworks/fabricator-apparatus';
import type { WritDoc } from '@shardworks/clerk-apparatus';
import type { RigTemplateEngine, SpiderEngineRunResult } from '@shardworks/spider-apparatus';
import type { LaboratoryTrialConfig, TrialFixtureDecl } from '../types.ts';

// ── Shared helpers ─────────────────────────────────────────────────

/**
 * Stable engine-id naming conventions. Every phase derives the ids
 * it needs from the trial config using these helpers — no
 * cross-phase data flow is required for naming.
 */
export const SETUP_ID = (fixtureId: string): string => `fixture-${fixtureId}-setup`;
export const TEARDOWN_ID = (fixtureId: string): string => `fixture-${fixtureId}-teardown`;
export const SCENARIO_ID = 'scenario';
export const PROBE_ID = (probeId: string): string => `probe-${probeId}`;
export const ARCHIVE_ID = 'archive';

/**
 * Convention: derive a fixture's teardown engine id from its setup
 * engine id when no explicit override is provided. Replaces a
 * trailing `-setup` with `-teardown`. If the setup id does not end
 * in `-setup`, appends `-teardown`.
 */
export function deriveTeardownEngineId(fixture: TrialFixtureDecl): string {
  if (fixture.teardownEngineId !== undefined) return fixture.teardownEngineId;
  if (fixture.engineId.endsWith('-setup')) {
    return fixture.engineId.replace(/-setup$/, '-teardown');
  }
  return `${fixture.engineId}-teardown`;
}

/**
 * Topologically sort fixtures by dependsOn. Every fixture appears
 * after all of its dependencies. Stable: among fixtures whose
 * dependencies are all already placed, declaration order is
 * preserved.
 *
 * Throws on cycles, unknown dependsOn references, or duplicate ids.
 */
export function topoSortFixtures(fixtures: TrialFixtureDecl[]): TrialFixtureDecl[] {
  const byId = new Map<string, TrialFixtureDecl>();
  for (const fixture of fixtures) {
    if (byId.has(fixture.id)) {
      throw new Error(`[lab] duplicate fixture id: "${fixture.id}"`);
    }
    byId.set(fixture.id, fixture);
  }

  for (const fixture of fixtures) {
    for (const dep of fixture.dependsOn ?? []) {
      if (!byId.has(dep)) {
        throw new Error(
          `[lab] fixture "${fixture.id}" dependsOn unknown fixture "${dep}"`,
        );
      }
    }
  }

  const result: TrialFixtureDecl[] = [];
  const placed = new Set<string>();
  const remaining = [...fixtures];

  while (remaining.length > 0) {
    const before = remaining.length;
    for (let i = 0; i < remaining.length; i += 1) {
      const fixture = remaining[i]!;
      const deps = fixture.dependsOn ?? [];
      if (deps.every((d) => placed.has(d))) {
        result.push(fixture);
        placed.add(fixture.id);
        remaining.splice(i, 1);
        i -= 1;
      }
    }
    if (remaining.length === before) {
      const ids = remaining.map((f) => f.id).join(', ');
      throw new Error(`[lab] fixture dependsOn cycle among: ${ids}`);
    }
  }

  return result;
}

/**
 * Read and validate the trial config from a writ. All phase
 * orchestrators share this entry path — fail-loud on missing
 * config so the manifest CLI's validation contract is the only
 * gate.
 */
function readTrialConfig(givens: Record<string, unknown>, phaseEngineId: string): {
  writ: WritDoc;
  config: LaboratoryTrialConfig;
} {
  const writ = givens.writ as WritDoc | undefined;
  if (!writ) {
    throw new Error(
      `[${phaseEngineId}] missing required given "writ" — the rig template must pass \${writ}.`,
    );
  }
  const config = (writ.ext as { laboratory?: { config?: LaboratoryTrialConfig } } | undefined)
    ?.laboratory?.config;
  if (!config) {
    throw new Error(
      `[${phaseEngineId}] trial writ ${writ.id} missing ext.laboratory.config — manifest CLI should reject this at post time.`,
    );
  }
  return { writ, config };
}

// ── Per-phase graft builders (pure; tested directly) ───────────────

/**
 * Build the setup phase's graft: one engine per fixture, in topo
 * order. A fixture's setup engine upstreams its dependsOn fixtures'
 * setup engines (or the head — `headEngineId` — when it has no
 * deps).
 */
export function buildSetupGraft(
  config: LaboratoryTrialConfig,
  headEngineId: string,
): { graft: RigTemplateEngine[]; ordered: TrialFixtureDecl[] } {
  const ordered = topoSortFixtures(config.fixtures);
  const graft: RigTemplateEngine[] = [];
  for (const fixture of ordered) {
    const deps = fixture.dependsOn ?? [];
    const upstream = deps.length > 0 ? deps.map(SETUP_ID) : [headEngineId];
    graft.push({
      id: SETUP_ID(fixture.id),
      designId: fixture.engineId,
      upstream,
      givens: fixture.givens,
    });
  }
  return { graft, ordered };
}

/**
 * Build the scenario phase's graft: one engine for the scenario.
 * Upstreams every fixture's setup engine, so it waits for the full
 * setup wave to complete. When there are no fixtures, upstreams
 * the head (the scenario phase orchestrator's own id).
 */
export function buildScenarioGraft(
  config: LaboratoryTrialConfig,
  headEngineId: string,
): RigTemplateEngine[] {
  const upstream =
    config.fixtures.length > 0
      ? topoSortFixtures(config.fixtures).map((f) => SETUP_ID(f.id))
      : [headEngineId];
  return [
    {
      id: SCENARIO_ID,
      designId: config.scenario.engineId,
      upstream,
      givens: config.scenario.givens,
    },
  ];
}

/**
 * Build the probes phase's graft: one engine per probe. Each probe
 * upstreams the scenario engine; probes themselves run in parallel.
 */
export function buildProbesGraft(
  config: LaboratoryTrialConfig,
): RigTemplateEngine[] {
  return config.probes.map((probe) => ({
    id: PROBE_ID(probe.id),
    designId: probe.engineId,
    upstream: [SCENARIO_ID],
    givens: probe.givens,
  }));
}

/**
 * Build the archive phase's graft: one archive engine. Upstreams
 * every probe engine; or the scenario engine when there are no
 * probes.
 */
export function buildArchiveGraft(
  config: LaboratoryTrialConfig,
): RigTemplateEngine[] {
  const upstream =
    config.probes.length > 0
      ? config.probes.map((p) => PROBE_ID(p.id))
      : [SCENARIO_ID];
  return [
    {
      id: ARCHIVE_ID,
      designId: config.archive.engineId,
      upstream,
      givens: config.archive.givens,
    },
  ];
}

/**
 * Build the teardown phase's graft: one engine per fixture, REVERSE
 * topo order, sequential chain rooted at archive. Sequential (not
 * parallel) so a teardown failure stops the chain rather than
 * shredding sibling teardowns concurrently.
 *
 * Returns the graft and the tail engine id (the rig's true end —
 * teardown phase sets graftTail to this for completion gating).
 */
export function buildTeardownGraft(
  config: LaboratoryTrialConfig,
): { graft: RigTemplateEngine[]; tail: string } {
  const ordered = topoSortFixtures(config.fixtures);
  const graft: RigTemplateEngine[] = [];
  let prevTail: string = ARCHIVE_ID;
  for (let i = ordered.length - 1; i >= 0; i -= 1) {
    const fixture = ordered[i]!;
    const id = TEARDOWN_ID(fixture.id);
    graft.push({
      id,
      designId: deriveTeardownEngineId(fixture),
      upstream: [prevTail],
      givens: fixture.givens,
    });
    prevTail = id;
  }
  return { graft, tail: prevTail };
}

// ── Phase orchestrator engines ─────────────────────────────────────

const setupPhaseEngine: EngineDesign = {
  id: 'lab.setup-phase',
  async run(givens, context): Promise<EngineRunResult> {
    const { config } = readTrialConfig(givens, 'lab.setup-phase');
    const { graft, ordered } = buildSetupGraft(config, context.engineId);
    const result: SpiderEngineRunResult = {
      status: 'completed',
      yields: {
        fixtureCount: ordered.length,
        fixtureIds: ordered.map((f) => f.id),
      },
      graft,
      // graftTail intentionally unset: the scenario engine has
      //   explicit upstream refs into each fixture-setup, so the
      //   scenario phase can fire immediately upon this engine's
      //   return without waiting for fixtures to complete first.
    };
    return result as EngineRunResult;
  },
};

const scenarioPhaseEngine: EngineDesign = {
  id: 'lab.scenario-phase',
  async run(givens, context): Promise<EngineRunResult> {
    const { config } = readTrialConfig(givens, 'lab.scenario-phase');
    const graft = buildScenarioGraft(config, context.engineId);
    const result: SpiderEngineRunResult = {
      status: 'completed',
      yields: { scenarioEngine: config.scenario.engineId },
      graft,
    };
    return result as EngineRunResult;
  },
};

const probesPhaseEngine: EngineDesign = {
  id: 'lab.probes-phase',
  async run(givens): Promise<EngineRunResult> {
    const { config } = readTrialConfig(givens, 'lab.probes-phase');
    const graft = buildProbesGraft(config);
    const result: SpiderEngineRunResult = {
      status: 'completed',
      yields: {
        probeCount: config.probes.length,
        probeIds: config.probes.map((p) => p.id),
      },
      graft,
    };
    return result as EngineRunResult;
  },
};

const archivePhaseEngine: EngineDesign = {
  id: 'lab.archive-phase',
  async run(givens): Promise<EngineRunResult> {
    const { config } = readTrialConfig(givens, 'lab.archive-phase');
    const graft = buildArchiveGraft(config);
    const result: SpiderEngineRunResult = {
      status: 'completed',
      yields: { archiveEngine: config.archive.engineId },
      graft,
    };
    return result as EngineRunResult;
  },
};

const teardownPhaseEngine: EngineDesign = {
  id: 'lab.teardown-phase',
  async run(givens): Promise<EngineRunResult> {
    const { config } = readTrialConfig(givens, 'lab.teardown-phase');
    const { graft, tail } = buildTeardownGraft(config);
    const result: SpiderEngineRunResult = {
      status: 'completed',
      yields: { teardownCount: config.fixtures.length },
      graft,
      // graftTail set: this is the rig's true end. Spider waits
      //   for `tail` to complete before considering the rig done.
      //   When there are no fixtures, tail equals ARCHIVE_ID — the
      //   archive engine is the last real work in that case.
      graftTail: tail,
    };
    return result as EngineRunResult;
  },
};

export const phaseEngines = {
  'lab.setup-phase': setupPhaseEngine,
  'lab.scenario-phase': scenarioPhaseEngine,
  'lab.probes-phase': probesPhaseEngine,
  'lab.archive-phase': archivePhaseEngine,
  'lab.teardown-phase': teardownPhaseEngine,
} as const;

/**
 * The Laboratory — public types.
 *
 * Two concerns live here:
 *
 *   1. The `trial` writ type configuration — its state machine, registered
 *      with the Clerk at startup. Mirrors the mandate lifecycle (`new →
 *      open → completed | failed | cancelled`, with `stuck` as a
 *      non-terminal "needs attention" state off `open`). Trials are leaves
 *      in v1 — the `experiment` parent type is reserved for v2 (see click
 *      c-momaacry).
 *
 *   2. The `ext.laboratory.config` schema — the structured trial
 *      configuration carried on every trial writ. Mirrors the YAML
 *      manifest shape exactly so the CLI's translation layer is a thin
 *      validator + post step.
 *
 * The legacy `LaboratoryConfig` (data-mirroring stub) is removed — that
 * plugin's no-op phase is over.
 *
 * See: experiments/infrastructure/setup-and-artifacts.md (the standalone-bash
 * spec the apparatus supersedes; its run.yaml shape is the template here).
 */

import type { WritTypeConfig } from '@shardworks/clerk-apparatus';

// ── Writ-type configuration ──────────────────────────────────────────

/** The writ-type name registered with the Clerk. */
export const TRIAL_TYPE_NAME = 'trial';

/**
 * The `trial` writ type. State machine mirrors mandate's
 * `new → open → completed/failed/cancelled` with `stuck` as a
 * non-terminal off `open`. Children-cascade behavior is included so
 * trials can be nested under a future `experiment` parent without a
 * config-level migration; in v1 trials are leaves and the cascade
 * triggers are inert.
 */
export const TRIAL_WRIT_TYPE_CONFIG: WritTypeConfig = {
  name: TRIAL_TYPE_NAME,
  states: [
    {
      name: 'new',
      classification: 'initial',
      allowedTransitions: ['open', 'cancelled'],
    },
    {
      name: 'open',
      classification: 'active',
      allowedTransitions: ['stuck', 'completed', 'failed', 'cancelled'],
    },
    {
      name: 'stuck',
      classification: 'active',
      attrs: ['stuck'],
      allowedTransitions: ['open', 'failed', 'cancelled'],
    },
    {
      name: 'completed',
      classification: 'terminal',
      attrs: ['success'],
      allowedTransitions: [],
    },
    {
      name: 'failed',
      classification: 'terminal',
      attrs: ['failure'],
      allowedTransitions: [],
    },
    {
      name: 'cancelled',
      classification: 'terminal',
      attrs: ['cancelled'],
      allowedTransitions: [],
    },
  ],
  childrenBehavior: {
    allSuccess: { transition: 'completed', copyResolution: true },
    anyFailure: { transition: 'failed', copyResolution: true },
    parentTerminal: {
      transition: 'cancelled',
      resolution: 'Automatically cancelled due to parent termination',
    },
  },
};

// ── ext.laboratory.config schema ─────────────────────────────────────
//
// The structured trial configuration. Mirrors the YAML manifest shape
// (see docs/laboratory/manifest-format.md once authored). Every field
// here will be validated by the manifest CLI before the trial writ is
// posted.

/**
 * Slug carried on every trial — used in disposable-surface naming
 * (codex repo, guild dir). Authored by the manifest. Length-limited at
 * the CLI boundary (see manifest-cli child); engines treat it as
 * already-validated input.
 *
 * Format target: lowercase kebab-case, alphanumeric + hyphen only,
 * 1–40 chars. Disposable-resource names of the shape
 * `trial-<slug>-<trialId-prefix>` slot below 63-char DNS / GH-repo
 * limits with margin.
 */
export type TrialSlug = string;

/**
 * One fixture declaration in a trial. Fixtures handle setup and
 * teardown of disposable surfaces (codex repos, test guilds, etc.)
 * and form a dependency DAG.
 *
 * Setup and teardown are paired engines. By convention the teardown
 * engine id is the setup id with `-setup` swapped for `-teardown`
 * (e.g. `lab.codex-setup` ↔ `lab.codex-teardown`). The `teardownEngineId`
 * field overrides this default when the convention doesn't fit.
 *
 * MVP0 ships trial-scope only — every fixture is fresh per trial,
 * torn down at trial end. The `scope` and `mutability` hooks are
 * reserved for v2 (see click c-mom19282).
 */
export interface TrialFixtureDecl {
  /** Fixture id within this trial. Referenced by `dependsOn`. */
  id: string;
  /** Setup engine design id (e.g. `'lab.codex-setup'`). */
  engineId: string;
  /** Override teardown engine id. Defaults to convention (`-setup` → `-teardown`). */
  teardownEngineId?: string;
  /** Givens passed to BOTH the setup and teardown engines. */
  givens: Record<string, unknown>;
  /** Other fixture ids that must be set up before this one. */
  dependsOn?: string[];
  /** Reserved for v2 — only `'trial'` valid in v1. */
  scope?: 'trial';
  /** Reserved for v2 — informational in v1. */
  mutability?: 'mutable' | 'read-only' | 'snapshotted';
}

/**
 * The scenario — what work runs inside the trial after fixtures are
 * up. In v1, scenarios are themselves engine designs (commission-post-
 * xguild + wait-for-writ-terminal-xguild are the canonical pair).
 * Future scenarios may compose multiple engine invocations.
 */
export interface TrialScenarioDecl {
  /** Engine design id to run as the scenario. */
  engineId: string;
  /** Givens passed to the scenario engine. */
  givens: Record<string, unknown>;
}

/** A probe — extracts data from one or more fixtures. */
export interface TrialProbeDecl {
  /** Probe id within this trial. */
  id: string;
  /** Engine design id (e.g. `'lab.probe-stacks-dump'`). */
  engineId: string;
  /** Givens passed to the probe engine. */
  givens: Record<string, unknown>;
}

/**
 * The archive declaration — where probe outputs land at trial end.
 * The engine and storage layout are being designed under click
 * c-momaa5o9; this shape is provisional.
 */
export interface TrialArchiveDecl {
  /** Engine design id (e.g. `'lab.archive'`). */
  engineId: string;
  /** Givens passed to the archive engine. */
  givens: Record<string, unknown>;
}

/**
 * The structured payload carried on every trial writ at
 * `ext.laboratory.config`. The manifest YAML on disk has the same
 * shape plus a top-level `description` field that lands on the writ
 * body instead of in `ext`.
 */
export interface LaboratoryTrialConfig {
  /** Trial slug (used in disposable-surface naming). */
  slug: TrialSlug;
  /** Fixtures to set up (DAG; topo-sort happens at template time). */
  fixtures: TrialFixtureDecl[];
  /** The workload that runs after setup. */
  scenario: TrialScenarioDecl;
  /** Probes to extract data. Run after the scenario reaches its end-condition. */
  probes: TrialProbeDecl[];
  /** Archive — where probe outputs go. */
  archive: TrialArchiveDecl;
}

// ── GuildConfig augmentation ─────────────────────────────────────────
//
// The Laboratory contributes no top-level guild.json config in v1.
// Trial-specific configuration lives on individual writs at
// `ext.laboratory.config`, not in guild config. Reserved for future
// global lab settings (e.g. default codex org, archive root path).

export interface LaboratoryConfig {
  /**
   * Reserved for v2. No fields read in v1 — present so guild.json
   * fragments that include an empty `laboratory: {}` block still
   * typecheck.
   */
  reserved?: never;
}

declare module '@shardworks/nexus-core' {
  interface GuildConfig {
    laboratory?: LaboratoryConfig;
  }
}

/**
 * @shardworks/laboratory-apparatus — The Laboratory.
 *
 * Apparatus for running trial-shaped experiments on guild
 * configurations. Audiences:
 *
 *   - **Nexus dev:** cost/quality tuning (P3 work, prompt evaluation,
 *     plugin variant comparison) — automate the experimental-
 *     infrastructure spec at experiments/infrastructure/setup-and-
 *     artifacts.md.
 *   - **End users:** evaluate their own prompts/plugins/configs by
 *     authoring trial manifests against a stable apparatus surface.
 *
 * Architecture (MVP0):
 *
 *   - One writ type: `trial` — a single execution unit. Lifecycle
 *     mirrors mandate. (Higher-level `experiment` grouping is parked
 *     for v2; click c-momaacry.)
 *   - One canonical rig template: `post-and-collect-default` —
 *     composes fixture-setup, scenario, probes, teardown, and archive
 *     engines from the writ's `ext.laboratory.config`.
 *   - Engines: fixtures (setup/teardown, DAG), scenario (cross-guild
 *     commission post + wait), probes (data extraction), archive
 *     (still in design at click c-momaa5o9).
 *
 * The plugin is currently a skeleton — only the trial writ-type
 * registration is wired. Engine designs, rig templates, and CLI tools
 * are added as their respective implementation children land.
 *
 * See: experiments/infrastructure/setup-and-artifacts.md
 */

import type { Plugin } from '@shardworks/nexus-core';
import { guild } from '@shardworks/nexus-core';
import type { ClerkApi } from '@shardworks/clerk-apparatus';

// ── Public type re-exports ───────────────────────────────────────────

export {
  TRIAL_TYPE_NAME,
  TRIAL_WRIT_TYPE_CONFIG,
} from './types.ts';
export type {
  LaboratoryConfig,
  LaboratoryTrialConfig,
  TrialFixtureDecl,
  TrialScenarioDecl,
  TrialProbeDecl,
  TrialArchiveDecl,
  TrialSlug,
} from './types.ts';

// ── Apparatus ────────────────────────────────────────────────────────

import { TRIAL_WRIT_TYPE_CONFIG } from './types.ts';
import { engines } from './engines/index.ts';
import { rigTemplates, rigTemplateMappings } from './template.ts';
import { tools } from './tools/index.ts';

const laboratoryPlugin: Plugin = {
  apparatus: {
    /**
     * Hard requires — apparatuses whose APIs the Laboratory's startup
     * code calls directly (clerk for writ-type registration), plus
     * those whose presence is structurally needed for the lab's
     * contributions to be useful (spider for rig-template execution,
     * fabricator for engine-design registration). Stacks is required
     * transitively via clerk.
     */
    requires: ['stacks', 'clerk', 'spider', 'fabricator'],

    /**
     * Recommended at startup; required at engine-execution time when
     * the relevant fixture or scenario engine actually fires. Marking
     * them as recommends (not requires) lets a guild start the lab
     * without these installed — the trials that touch the missing
     * surface fail when their engine runs, not at startup.
     */
    recommends: ['codexes', 'animator'],

    /**
     * Kit contributions wired up:
     *
     *   - `engines`              — every Laboratory engine design
     *                               (5 phase orchestrators + the
     *                               work-engine stubs that get
     *                               grafted by them). Stubs land
     *                               their real behavior under their
     *                               respective implementation clicks.
     *   - `rigTemplates`         — `post-and-collect-default` —
     *                               enumerates the five phase
     *                               orchestrators in sequence.
     *   - `rigTemplateMappings`  — `trial` → `post-and-collect-default`.
     *   - `tools`                — the manifest CLI surface
     *                               (`nsg lab trial-post`).
     */
    supportKit: {
      engines,
      rigTemplates,
      rigTemplateMappings,
      tools,
    },

    async start() {
      // Register the `trial` writ type with the Clerk. The
      // registration window closes at framework `phase:started`;
      // calling later throws.
      const clerk = guild().apparatus<ClerkApi>('clerk');
      clerk.registerWritType(TRIAL_WRIT_TYPE_CONFIG);
    },
  },
};

export default laboratoryPlugin;

/**
 * The Laboratory's rig templates.
 *
 * MVP0 ships ONE template: `post-and-collect-default`. Its engine
 * list IS the trial-flow backbone — five phase orchestrators
 * (setup → scenario → probes → archive → teardown) wired in
 * sequence. Each phase orchestrator is a clockwork engine: it
 * reads `writ.ext.laboratory.config`, computes the per-phase
 * graft, and returns immediately. The grafted engines do the
 * real work; the template documents the flow.
 *
 * Why the backbone is in the template (not in a single
 * orchestrator):
 *
 *   - The template is the user-facing shape document for a trial.
 *     With phases visible, reading the template tells you "this
 *     rig runs setup, then scenario, then probes, then archive,
 *     then teardown."
 *   - Per-phase failure visibility: oculus and introspection tools
 *     see the phase backbone in the rig's engine list; "the probes
 *     phase failed" is a more useful signal than "the orchestrator
 *     failed somewhere."
 *   - Each phase orchestrator implementation is cohesive (DAG
 *     sort, parallel scatter, reverse-sequential chain) — splitting
 *     them avoids one big function with phase-mode flags.
 *   - Sets up an extension point: a future plugin contributing
 *     `lab.warmup-phase` (or similar) could slot into a custom
 *     template alongside the existing phases.
 *
 * Cross-phase data flow happens at the work-engine layer, not the
 * orchestrator layer. All grafted engines share a single namespace,
 * so e.g. the scenario engine's upstream points directly at each
 * fixture-setup engine — phase orchestrators don't need to relay
 * yields between phases.
 *
 * Rig template name vs writ-type mapping: the Spider qualifies
 * kit-contributed template keys by plugin id when storing them in
 * its registry. The unqualified key `'post-and-collect-default'`
 * registers as `'laboratory.post-and-collect-default'`. The mapping
 * value below uses the unqualified form because spider.ts joins
 * the plugin id when resolving mappings (matches astrolabe's
 * convention).
 */

import type { RigTemplate } from '@shardworks/spider-apparatus';

/**
 * The post-and-collect-default rig template — five phase
 * orchestrators in sequence.
 *
 * Each phase orchestrator reads the trial's `ext.laboratory.config`,
 * computes its phase's graft, and returns. graftTail is set only
 * on `lab.teardown-phase` (the rig's true end) — intermediate
 * phases let the next phase fire immediately, since real
 * work-engines wait on explicit upstream refs.
 */
export const POST_AND_COLLECT_DEFAULT: RigTemplate = {
  engines: [
    {
      id: 'setup-phase',
      designId: 'lab.setup-phase',
      // Head engine — no upstream.
      givens: { writ: '${writ}' },
    },
    {
      id: 'scenario-phase',
      designId: 'lab.scenario-phase',
      upstream: ['setup-phase'],
      givens: { writ: '${writ}' },
    },
    {
      id: 'probes-phase',
      designId: 'lab.probes-phase',
      upstream: ['scenario-phase'],
      givens: { writ: '${writ}' },
    },
    {
      id: 'archive-phase',
      designId: 'lab.archive-phase',
      upstream: ['probes-phase'],
      givens: { writ: '${writ}' },
    },
    {
      id: 'teardown-phase',
      designId: 'lab.teardown-phase',
      upstream: ['archive-phase'],
      givens: { writ: '${writ}' },
    },
  ],
  // resolutionEngine intentionally unset — the Spider falls back
  //   to the last completed engine, which is the final teardown
  //   (or archive when there are no fixtures), via the
  //   teardown-phase orchestrator's graftTail.
};

/** The Laboratory's rig templates, keyed by unqualified template name. */
export const rigTemplates: Record<string, RigTemplate> = {
  'post-and-collect-default': POST_AND_COLLECT_DEFAULT,
};

/** Writ-type → unqualified-template-name mappings. */
export const rigTemplateMappings: Record<string, string> = {
  trial: 'post-and-collect-default',
};

