1	/**
2	 * Trial manifest — YAML format, zod schema, parser, and validator.
3	 *
4	 * The manifest is the authoring surface for trials. Its shape mirrors
5	 * `LaboratoryTrialConfig` exactly, with two additions:
6	 *
7	 *   - `description` — optional prose that becomes the trial writ's
8	 *     body (free-form, no structural meaning).
9	 *   - `title` — optional short title that becomes the trial writ's
10	 *     title (defaults to `Trial: <slug>`).
11	 *
12	 * The manifest also accepts optional `parentId` and `codex` fields
13	 * for clerk's writ-post API; both are passed through to clerk.post
14	 * unchanged.
15	 *
16	 * Manifest YAML example:
17	 *
18	 *     slug: orientation-suppression-strong-prompt
19	 *     title: P3 orientation suppression — strong prompt variant
20	 *     description: |
21	 *       Tests whether an imperative anti-orientation directive in the
22	 *       implementer handoff produces productive work in <5 turns.
23	 *
24	 *     fixtures:
25	 *       - id: codex
26	 *         engineId: lab.codex-setup
27	 *         givens:
28	 *           upstreamRepo: shardworks/nexus
29	 *           baseSha: <40-char>
30	 *
31	 *       - id: test-guild
32	 *         engineId: lab.guild-setup
33	 *         dependsOn: [codex]
34	 *         givens:
35	 *           plugins: [...]
36	 *           config: { ... }
37	 *           files: [...]
38	 *
39	 *     scenario:
40	 *       engineId: lab.commission-post-xguild
41	 *       givens:
42	 *         briefPath: files/brief.md
43	 *
44	 *     probes:
45	 *       - id: stacks
46	 *         engineId: lab.probe-stacks-dump
47	 *         givens:
48	 *           outputPath: stacks-export/
49	 *
50	 *     archive:
51	 *       engineId: lab.archive
52	 *       givens: {}
53	 *
54	 * The parser:
55	 *   1. Reads the YAML file.
56	 *   2. Parses it into a JS object.
57	 *   3. Validates against `manifestSchema`.
58	 *   4. Cross-validates fixture DAG (cycles, unknown deps, dup ids).
59	 *   5. Splits into a writ-post shape and the trial config that goes
60	 *      under `ext.laboratory.config`.
61	 */
62	
63	import { readFile } from 'node:fs/promises';
64	import { parse as parseYaml } from 'yaml';
65	import { z } from 'zod';
66	import type {
67	  LaboratoryTrialConfig,
68	  TrialFixtureDecl,
69	  TrialScenarioDecl,
70	  TrialProbeDecl,
71	  TrialArchiveDecl,
72	} from './types.ts';
73	import { topoSortFixtures } from './engines/phases.ts';
74	
75	// ── Slug ──────────────────────────────────────────────────────────
76	
77	/**
78	 * Trial slug rules (used in disposable-surface naming):
79	 *   - lowercase alphanumeric and hyphens only
80	 *   - must start with a letter
81	 *   - 1–40 characters
82	 *
83	 * `trial-<slug>-<trialId-prefix>` (the codex/repo naming format)
84	 * with a 40-char slug and an 8-char id-prefix sums to 55 chars,
85	 * comfortably under the 63-char DNS / GH-repo limit.
86	 */
87	export const SLUG_PATTERN = /^[a-z][a-z0-9-]{0,39}$/;
88	export const SLUG_MAX_LENGTH = 40;
89	
90	const slugSchema = z.string().regex(
91	  SLUG_PATTERN,
92	  'must be lowercase kebab-case (start with a letter; alphanumeric and hyphens; ≤40 chars)',
93	);
94	
95	// ── Sub-schemas ───────────────────────────────────────────────────
96	
97	const givensSchema = z.record(z.string(), z.unknown()).default({});
98	
99	const fixtureSchema = z.object({
100	  id: z
101	    .string()
102	    .min(1, 'must be non-empty')
103	    .regex(/^[a-z][a-z0-9-]{0,39}$/, 'fixture id must be kebab-case (≤40 chars)'),
104	  engineId: z.string().min(1, 'engineId is required'),
105	  teardownEngineId: z.string().min(1).optional(),
106	  givens: givensSchema,
107	  dependsOn: z.array(z.string()).optional(),
108	  scope: z.literal('trial').optional(),
109	  mutability: z.enum(['mutable', 'read-only', 'snapshotted']).optional(),
110	}) satisfies z.ZodType<TrialFixtureDecl>;
111	
112	const scenarioSchema = z.object({
113	  engineId: z.string().min(1, 'engineId is required'),
114	  givens: givensSchema,
115	}) satisfies z.ZodType<TrialScenarioDecl>;
116	
117	const probeSchema = z.object({
118	  id: z
119	    .string()
