1	/**
2	 * Tests for the per-phase graft builders and the topo sort helper.
3	 *
4	 * The graft builders are pure functions — given a trial config (and
5	 * the head engine id for setup/scenario), each returns the
6	 * RigTemplateEngine[] its phase contributes to the rig. Together the
7	 * five graft builders produce a flat engine list equivalent to what
8	 * the previous one-engine orchestrator produced; they're tested
9	 * piece-wise here.
10	 */
11	
12	import { describe, it } from 'node:test';
13	import assert from 'node:assert/strict';
14	import {
15	  buildArchiveGraft,
16	  buildProbesGraft,
17	  buildScenarioGraft,
18	  buildSetupGraft,
19	  buildTeardownGraft,
20	  topoSortFixtures,
21	} from './phases.ts';
22	import type { LaboratoryTrialConfig, TrialFixtureDecl } from '../types.ts';
23	
24	const HEAD = 'phase-head';
25	
26	function trialConfig(over: Partial<LaboratoryTrialConfig> = {}): LaboratoryTrialConfig {
27	  return {
28	    slug: 'test',
29	    fixtures: [],
30	    scenario: { engineId: 'lab.commission-post-xguild', givens: {} },
31	    probes: [],
32	    archive: { engineId: 'lab.archive', givens: {} },
33	    ...over,
34	  };
35	}
36	
37	function fixture(id: string, over: Partial<TrialFixtureDecl> = {}): TrialFixtureDecl {
38	  return {
39	    id,
40	    engineId: `lab.${id}-setup`,
41	    givens: {},
42	    ...over,
43	  };
44	}
45	
46	// ── topoSortFixtures ────────────────────────────────────────────────
47	
48	describe('topoSortFixtures', () => {
49	  it('preserves declaration order when there are no deps', () => {
50	    const fixtures = [fixture('a'), fixture('b'), fixture('c')];
51	    const sorted = topoSortFixtures(fixtures);
52	    assert.deepEqual(
53	      sorted.map((f) => f.id),
54	      ['a', 'b', 'c'],
55	    );
56	  });
57	
58	  it('places dependencies before dependents', () => {
59	    const fixtures = [
60	      fixture('child', { dependsOn: ['parent'] }),
61	      fixture('parent'),
62	    ];
63	    const sorted = topoSortFixtures(fixtures);
64	    assert.deepEqual(
65	      sorted.map((f) => f.id),
66	      ['parent', 'child'],
67	    );
68	  });
69	
70	  it('handles a deep chain', () => {
71	    const fixtures = [
72	      fixture('d', { dependsOn: ['c'] }),
73	      fixture('c', { dependsOn: ['b'] }),
74	      fixture('b', { dependsOn: ['a'] }),
75	      fixture('a'),
76	    ];
77	    const sorted = topoSortFixtures(fixtures);
78	    assert.deepEqual(
79	      sorted.map((f) => f.id),
80	      ['a', 'b', 'c', 'd'],
81	    );
82	  });
83	
84	  it('handles diamond dependencies', () => {
85	    const fixtures = [
86	      fixture('top'),
87	      fixture('left', { dependsOn: ['top'] }),
88	      fixture('right', { dependsOn: ['top'] }),
89	      fixture('bottom', { dependsOn: ['left', 'right'] }),
90	    ];
91	    const sorted = topoSortFixtures(fixtures);
92	    const positionOf = (id: string) => sorted.findIndex((f) => f.id === id);
93	    assert.ok(positionOf('top') < positionOf('left'));
94	    assert.ok(positionOf('top') < positionOf('right'));
95	    assert.ok(positionOf('left') < positionOf('bottom'));
96	    assert.ok(positionOf('right') < positionOf('bottom'));
97	  });
98	
99	  it('throws on a cycle', () => {
100	    const fixtures = [
101	      fixture('a', { dependsOn: ['b'] }),
102	      fixture('b', { dependsOn: ['a'] }),
103	    ];
104	    assert.throws(() => topoSortFixtures(fixtures), /cycle/i);
105	  });
106	
107	  it('throws on unknown dependsOn reference', () => {
108	    const fixtures = [fixture('a', { dependsOn: ['ghost'] })];
109	    assert.throws(() => topoSortFixtures(fixtures), /unknown fixture "ghost"/);
110	  });
111	
112	  it('throws on duplicate fixture ids', () => {
113	    const fixtures = [fixture('a'), fixture('a')];
114	    assert.throws(() => topoSortFixtures(fixtures), /duplicate fixture id/);
115	  });
116	});
117	
118	// ── buildSetupGraft ────────────────────────────────────────────────
119	
120	describe('buildSetupGraft', () => {
121	  it('produces empty graft for no fixtures', () => {
122	    const { graft, ordered } = buildSetupGraft(trialConfig(), HEAD);
123	    assert.deepEqual(graft, []);
124	    assert.deepEqual(ordered, []);
125	  });
126	
127	  it('first wave of fixture-setups upstreams the head engine', () => {
128	    const { graft } = buildSetupGraft(
129	      trialConfig({ fixtures: [fixture('codex'), fixture('test-guild')] }),
130	      HEAD,
131	    );
132	    const codexSetup = graft.find((e) => e.id === 'fixture-codex-setup')!;
133	    const guildSetup = graft.find((e) => e.id === 'fixture-test-guild-setup')!;
134	    assert.deepEqual(codexSetup.upstream, [HEAD]);
135	    assert.deepEqual(guildSetup.upstream, [HEAD]);
136	  });
137	
138	  it('dependent fixture upstreams its dependency', () => {
139	    const { graft } = buildSetupGraft(
140	      trialConfig({
141	        fixtures: [
142	          fixture('codex'),
143	          fixture('test-guild', { dependsOn: ['codex'] }),
144	        ],
145	      }),
146	      HEAD,
147	    );
148	    const guildSetup = graft.find((e) => e.id === 'fixture-test-guild-setup')!;
149	    assert.deepEqual(guildSetup.upstream, ['fixture-codex-setup']);
150	  });
151	
152	  it('returns ordered fixtures matching topo sort', () => {
153	    const { ordered } = buildSetupGraft(
154	      trialConfig({
155	        fixtures: [
156	          fixture('child', { dependsOn: ['parent'] }),
157	          fixture('parent'),
158	        ],
159	      }),
160	      HEAD,
161	    );
162	    assert.deepEqual(ordered.map((f) => f.id), ['parent', 'child']);
163	  });
164	
165	  it('passes fixture givens to the setup engine', () => {
166	    const givens = { name: 'codex', remoteUrl: 'git@github.com:foo/bar' };
167	    const { graft } = buildSetupGraft(
168	      trialConfig({ fixtures: [fixture('codex', { givens })] }),
169	      HEAD,
170	    );
171	    const setup = graft.find((e) => e.id === 'fixture-codex-setup')!;
172	    assert.deepEqual(setup.givens, givens);
173	  });
174	});
175	
176	// ── buildScenarioGraft ─────────────────────────────────────────────
177	
178	describe('buildScenarioGraft', () => {
179	  it('upstreams the head engine when no fixtures', () => {
180	    const graft = buildScenarioGraft(trialConfig(), HEAD);
181	    assert.equal(graft.length, 1);
182	    assert.equal(graft[0]!.id, 'scenario');
183	    assert.deepEqual(graft[0]!.upstream, [HEAD]);
184	  });
185	
186	  it('upstreams every fixture-setup', () => {
187	    const graft = buildScenarioGraft(
188	      trialConfig({ fixtures: [fixture('codex'), fixture('test-guild')] }),
189	      HEAD,
190	    );
191	    assert.deepEqual(
192	      [...graft[0]!.upstream!].sort(),
193	      ['fixture-codex-setup', 'fixture-test-guild-setup'].sort(),
194	    );
195	  });
196	
197	  it('passes scenario givens through unchanged', () => {
198	    const graft = buildScenarioGraft(
199	      trialConfig({
200	        scenario: {
201	          engineId: 'lab.commission-post-xguild',
202	          givens: { briefPath: 'files/brief.md' },
203	        },
204	      }),
205	      HEAD,
206	    );
207	    assert.deepEqual(graft[0]!.givens, { briefPath: 'files/brief.md' });
208	  });
209	
210	  it('uses the scenario engine id from config', () => {
211	    const graft = buildScenarioGraft(
212	      trialConfig({
213	        scenario: { engineId: 'custom.scenario', givens: {} },
214	      }),
215	      HEAD,
216	    );
217	    assert.equal(graft[0]!.designId, 'custom.scenario');
218	  });
219	});
220	
221	// ── buildProbesGraft ───────────────────────────────────────────────
222	
223	describe('buildProbesGraft', () => {
224	  it('produces empty graft for no probes', () => {
225	    const graft = buildProbesGraft(trialConfig());
226	    assert.deepEqual(graft, []);
227	  });
228	
229	  it('every probe upstreams scenario; probes run parallel to each other', () => {
230	    const graft = buildProbesGraft(
231	      trialConfig({
232	        probes: [
233	          { id: 'stacks', engineId: 'lab.probe-stacks-dump', givens: {} },
234	          { id: 'git', engineId: 'lab.probe-git-range', givens: {} },
235	        ],
236	      }),
237	    );
238	    const stacks = graft.find((e) => e.id === 'probe-stacks')!;
239	    const git = graft.find((e) => e.id === 'probe-git')!;
240	    assert.deepEqual(stacks.upstream, ['scenario']);
241	    assert.deepEqual(git.upstream, ['scenario']);
242	  });
243	
244	  it('passes probe givens through unchanged', () => {
245	    const graft = buildProbesGraft(
246	      trialConfig({
247	        probes: [
248	          {
249	            id: 'stacks',
250	            engineId: 'lab.probe-stacks-dump',
251	            givens: { outputPath: 'stacks-export/' },
252	          },
253	        ],
254	      }),
255	    );
256	    assert.deepEqual(graft[0]!.givens, { outputPath: 'stacks-export/' });
257	  });
258	});
259	
260	// ── buildArchiveGraft ──────────────────────────────────────────────
261	
262	describe('buildArchiveGraft', () => {
263	  it('upstreams scenario when no probes', () => {
264	    const graft = buildArchiveGraft(trialConfig());
265	    assert.equal(graft.length, 1);
266	    assert.equal(graft[0]!.id, 'archive');
267	    assert.deepEqual(graft[0]!.upstream, ['scenario']);
268	  });
269	
270	  it('upstreams every probe when probes exist', () => {
271	    const graft = buildArchiveGraft(
272	      trialConfig({
273	        probes: [
274	          { id: 'stacks', engineId: 'lab.probe-stacks-dump', givens: {} },
275	          { id: 'git', engineId: 'lab.probe-git-range', givens: {} },
276	        ],
277	      }),
278	    );
279	    assert.deepEqual(
280	      [...graft[0]!.upstream!].sort(),
281	      ['probe-git', 'probe-stacks'],
282	    );
283	  });
284	
285	  it('passes archive givens through unchanged', () => {
286	    const graft = buildArchiveGraft(
287	      trialConfig({
288	        archive: { engineId: 'lab.archive', givens: { target: 'sanctum' } },
289	      }),
290	    );
291	    assert.deepEqual(graft[0]!.givens, { target: 'sanctum' });
292	  });
293	});
294	
295	// ── buildTeardownGraft ─────────────────────────────────────────────
296	
297	describe('buildTeardownGraft', () => {
298	  it('returns archive as tail when there are no fixtures', () => {
299	    const { graft, tail } = buildTeardownGraft(trialConfig());
300	    assert.deepEqual(graft, []);
301	    assert.equal(tail, 'archive');
302	  });
303	
304	  it('teardowns run in reverse topo order, sequential chain rooted at archive', () => {
305	    const { graft, tail } = buildTeardownGraft(
306	      trialConfig({
307	        fixtures: [
308	          fixture('codex'),
309	          fixture('test-guild', { dependsOn: ['codex'] }),
310	        ],
311	      }),
312	    );
313	    const guildTeardown = graft.find((e) => e.id === 'fixture-test-guild-teardown')!;
314	    const codexTeardown = graft.find((e) => e.id === 'fixture-codex-teardown')!;
315	    assert.deepEqual(guildTeardown.upstream, ['archive']);
316	    assert.deepEqual(codexTeardown.upstream, ['fixture-test-guild-teardown']);
317	    assert.equal(tail, 'fixture-codex-teardown');
318	  });
319	
320	  it('derives teardown engine id by replacing -setup with -teardown', () => {
321	    const { graft } = buildTeardownGraft(
322	      trialConfig({ fixtures: [fixture('codex')] }),
323	    );
324	    const teardown = graft.find((e) => e.id === 'fixture-codex-teardown')!;
325	    assert.equal(teardown.designId, 'lab.codex-teardown');
326	  });
327	
328	  it('falls back to "<engineId>-teardown" when setup id does not end in -setup', () => {
329	    const { graft } = buildTeardownGraft(
330	      trialConfig({
331	        fixtures: [fixture('weird', { engineId: 'lab.bootstrap' })],
332	      }),
333	    );
334	    const teardown = graft.find((e) => e.id === 'fixture-weird-teardown')!;
335	    assert.equal(teardown.designId, 'lab.bootstrap-teardown');
336	  });
337	
338	  it('honors an explicit teardownEngineId override', () => {
339	    const { graft } = buildTeardownGraft(
340	      trialConfig({
