363	// ── End-to-end shape — five phases yield the same flat graph ───────
364	
365	describe('staged-phase composition matches the unified flat graph', () => {
366	  it('two-fixture trial composes setup → scenario → probes → archive → teardown correctly', () => {
367	    const config = trialConfig({
368	      fixtures: [
369	        fixture('codex'),
