380	    const probesGraft = buildProbesGraft(config);
381	    const archiveGraft = buildArchiveGraft(config);
382	    const { graft: teardownGraft, tail } = buildTeardownGraft(config);
383	
384	    // Combined runtime engine list (ignoring the orchestrators
385	    // themselves; those live in the static template).
386	    const allWorkEngines = [
387	      ...setupGraft,
388	      ...scenarioGraft,
389	      ...probesGraft,
