1	/**
2	 * nsg init — create a new guild.
3	 *
4	 * A framework command — hardcoded in the CLI, not discovered via plugins.
5	 *
6	 * Writes the minimum viable guild: directory structure, guild.json,
7	 * package.json, .gitignore. Does NOT git init, install bundles, create
8	 * the database, or instantiate animas — those are separate steps.
9	 *
10	 * After init, the user runs `nsg plugin install` to add capabilities.
11	 */
12	
13	import fs from 'node:fs';
14	import path from 'node:path';
15	import { execFileSync } from 'node:child_process';
16	import { tool } from '@shardworks/tools-apparatus';
17	import { VERSION, createInitialGuildConfig, writeGuildConfig } from '@shardworks/nexus-core';
18	import { z } from 'zod';
19	
20	const DEFAULT_MODEL = 'sonnet';
21	
22	export default tool({
23	  name: 'init',
24	  description: 'Create a new guild — directory structure, guild.json, and package.json',
25	  callableBy: ['patron'],
26	  params: {
27	    path: z.string().describe('Directory path for the new guild'),
28	    name: z.string().optional().describe('Guild name (defaults to directory basename)'),
29	    model: z.string().optional().describe('Default model for anima sessions (default: sonnet)'),
30	  },
31	  handler: async (params) => {
32	    const home = path.resolve(params.path);
33	    const name = params.name ?? path.basename(home);
34	    const model = params.model ?? DEFAULT_MODEL;
35	
36	    // Validate target
37	    if (fs.existsSync(home)) {
38	      const entries = fs.readdirSync(home);
39	      if (entries.length > 0) {
40	        throw new Error(`${home} exists and is not empty.`);
41	      }
42	    }
43	
44	    // Create guild root
45	    fs.mkdirSync(home, { recursive: true });
46	
47	    // .nexus infrastructure (gitignored)
48	    fs.mkdirSync(path.join(home, '.nexus'), { recursive: true });
49	
50	    // guild.json — V2 format: plugin-centric, model in settings
51	    const guildConfig = createInitialGuildConfig(name, VERSION, model);
52	    writeGuildConfig(home, guildConfig);
53	
54	    // package.json — makes the guild an npm project so plugins install as deps.
55	    // If running from a published version, pin @shardworks/nexus so nsg is
56	    // available in the guild's node_modules/.bin without a global install.
57	    const dependencies: Record<string, string> = {};
58	    if (VERSION !== '0.0.0') {
59	      dependencies['@shardworks/nexus'] = `^${VERSION}`;
60	    }
61	
62	    const packageJson = {
63	      name: `guild-${name}`,
64	      private: true,
65	      version: '0.0.0',
66	      type: 'module',
67	      dependencies,
68	    };
69	    fs.writeFileSync(
70	      path.join(home, 'package.json'),
71	      JSON.stringify(packageJson, null, 2) + '\n',
72	    );
73	
74	    // .gitignore
75	    fs.writeFileSync(
76	      path.join(home, '.gitignore'),
77	      ['node_modules/', '.nexus/', ''].join('\n'),
78	    );
79	
80	    // npm install to get dependencies into node_modules
81	    if (Object.keys(dependencies).length > 0) {
82	      execFileSync('npm', ['install'], { cwd: home, stdio: 'pipe' });
83	    }
84	
85	    const lines = [
86	      `Guild "${name}" created at ${home}`,
87	      '',
88	      `  cd ${params.path}`,
89	      '  git init                                        # if you want version control',
