      { a: 1, b: 99, c: 3 },
    );
  });

  it('recurses into plain object values', () => {
    assert.deepEqual(
      deepMerge(
        { plugins: { astrolabe: { patronRole: 'patron' } } },
        { plugins: { astrolabe: { model: 'sonnet' }, animator: {} } },
      ),
