2	import { guild, shortId } from '@shardworks/nexus-core';
3	import { tool } from '@shardworks/tools-apparatus';
4	import type {
5	  ClerkApi,
6	  WritDoc,
7	  WritLinks,
8	  WritPhase,
9	  WritReferenceWithPresentation,
10	  WritPresentationClassification,
11	} from '../types.ts';
12	import { derivePresentation } from '../writ-presentation.ts';
13	
14	/**
15	 * Shape returned by writ-show in JSON mode. Preserves the existing
16	 * top-level `WritDoc` fields and adds the presentation projection,
17	 * parent reference, children summary/items, and links sub-document.
18	 */
19	interface WritShowResult extends WritDoc {
20	  classification: WritPresentationClassification;
21	  allowedTransitions: string[];
22	  links: WritLinks;
23	  parent: WritReferenceWithPresentation | null;
24	  children: { summary: Record<WritPhase, number>; items: WritReferenceWithPresentation[] };
25	}
26	
27	/**
28	 * Render the lifecycle-aware text view of a writ-show response per D3:
29	 * type, state with classification + attrs annotation, title, codex,
30	 * parent reference, timestamps, resolution, allowed-transitions list,
31	 * descendant phase summary, and links.
32	 *
33	 * The state annotation reads classification verbatim from the embedded
34	 * projection and reads attrs from the writ's registered type config (a
35	 * single closure-captured lookup). Unknown classifications surface as
36	 * `unknown` and the renderer continues — matching writ-tree's D17
37	 * fallback so a single legacy writ does not abort the detail view.
38	 */
39	function renderShow(
40	  result: WritShowResult,
41	  attrs: readonly string[],
42	): string {
43	  const lines: string[] = [];
44	
45	  // ── Identity row ──
46	  lines.push(`Writ:    ${result.title ?? ''}`);
47	  lines.push(`Id:      ${shortId(result.id)}  (${result.id})`);
48	  lines.push(`Type:    ${result.type}`);
49	
50	  // ── State annotation: phase, classification, attrs ──
51	  const attrSegment = attrs.length > 0 ? `, attrs: [${attrs.join(', ')}]` : '';
52	  lines.push(`State:   ${result.phase}  (classification: ${result.classification}${attrSegment})`);
53	
54	  // ── Allowed transitions (empty for terminal/unknown) ──
55	  const transitionsLabel = result.allowedTransitions.length === 0
56	    ? '(none — terminal or unknown state)'
57	    : result.allowedTransitions.join(', ');
58	  lines.push(`Transitions: ${transitionsLabel}`);
59	
60	  if (result.codex) {
61	    lines.push(`Codex:   ${result.codex}`);
62	  }
63	  if (result.parent) {
64	    lines.push(`Parent:  ${shortId(result.parent.id)}  ${result.parent.title}  (${result.parent.phase})`);
65	  }
66	
67	  // ── Timestamps ──
68	  lines.push('');
69	  lines.push(`Created: ${result.createdAt}`);
70	  lines.push(`Updated: ${result.updatedAt}`);
71	  if (result.resolvedAt) {
72	    lines.push(`Resolved: ${result.resolvedAt}`);
73	  }
74	  if (result.resolution) {
75	    lines.push(`Resolution: ${result.resolution}`);
76	  }
77	
78	  // ── Body ──
79	  if (result.body) {
80	    lines.push('');
81	    lines.push('Body:');
82	    for (const ln of result.body.split('\n')) lines.push(`  ${ln}`);
83	  }
84	
85	  // ── Descendant phase summary ──
86	  const summaryEntries = Object.entries(result.children.summary);
87	  if (summaryEntries.length > 0) {
88	    lines.push('');
89	    lines.push('Descendants:');
90	    for (const [phase, count] of summaryEntries) {
91	      lines.push(`  ${phase}: ${count}`);
92	    }
93	  }
94	
95	  // ── Direct-children list ──
96	  if (result.children.items.length > 0) {
97	    lines.push('');
98	    lines.push('Children:');
99	    for (const child of result.children.items) {
100	      lines.push(`  ${shortId(child.id)}  ${child.phase.padEnd(10)}  ${child.title}`);
101	    }
102	  }
103	
104	  // ── Links ──
105	  const outbound = result.links.outbound ?? [];
106	  const inbound = result.links.inbound ?? [];
107	  if (outbound.length > 0 || inbound.length > 0) {
108	    lines.push('');
109	    lines.push('Links:');
110	    for (const l of outbound) {
111	      lines.push(`  → ${shortId(l.targetId)}  (${l.label})`);
112	    }
113	    for (const l of inbound) {
114	      lines.push(`  ← ${shortId(l.sourceId)}  (${l.label})`);
115	    }
116	  }
117	
118	  return lines.join('\n');
119	}
120	
121	export default tool({
122	  name: 'writ-show',
123	  description: 'Show full detail for a writ',
124	  instructions:
125	    'Returns the complete writ record including its current phase, timestamps, body text, ' +
126	    'resolution, parent context, and children. The `children.summary` field is a ' +
127	    'phase-keyed count of the entire descendant subtree beneath this writ (grandchildren ' +
128	    'and deeper included; the writ itself is excluded). The `children.items` list stays ' +
129	    'scoped to direct children only. The default `--format text` renders a lifecycle-aware ' +
130	    'block (state classification + attrs, allowed transitions, descendant summary, links); ' +
131	    'pass `--format json` for the structured response.',
132	  params: {
133	    id: z.string().describe('Writ id'),
134	    format: z
135	      .enum(['text', 'json'])
136	      .default('text')
137	      .describe('Output format. "text" renders the lifecycle-aware block (default). "json" returns the structured response.'),
138	  },
139	  permission: 'read',
140	  handler: async (params) => {
141	    const clerk = guild().apparatus<ClerkApi>('clerk');
142	    const resolvedId = await clerk.resolveId(params.id);
143	    const [writ, links, summary] = await Promise.all([
144	      clerk.show(resolvedId),
145	      clerk.links(resolvedId),
146	      clerk.countDescendantsByPhase(resolvedId),
147	    ]);
148	
149	    const lookupConfig = (name: string) => clerk.getWritTypeConfig(name);
150	
151	    /**
152	     * Project a writ-shaped record onto the parent/child reference shape
153	     * with embedded presentation fields. Used both for the `parent`
154	     * context and each entry in `children.items` so a renderer can pick
155	     * badge classes uniformly without a second registry lookup.
156	     */
157	    function presentReference(
158	      ref: { id: string; title: string; type: string; phase: string },
159	    ): WritReferenceWithPresentation {
160	      const projection = derivePresentation(ref, lookupConfig);
161	      return {
162	        id: ref.id,
163	        title: ref.title,
164	        type: ref.type,
165	        phase: ref.phase,
166	        classification: projection.classification,
167	        allowedTransitions: projection.allowedTransitions,
168	      };
169	    }
170	
171	    // Parent context
172	    let parent: WritReferenceWithPresentation | null = null;
173	    if (writ.parentId) {
174	      const parentWrit = await clerk.show(writ.parentId);
175	      parent = presentReference(parentWrit);
176	    }
177	
178	    // Direct-children list — `items` stays direct-children-only. The subtree-wide
179	    // phase tally lives in `summary` (computed via clerk.countDescendantsByPhase).
180	    const childWrits = await clerk.list({ parentId: writ.id, limit: 1000 });
181	    const items: WritReferenceWithPresentation[] = childWrits.map(presentReference);
182	
183	    // Top-level writ also carries classification + allowedTransitions so
184	    // the detail-view renderer can derive its action buttons from a
185	    // single shape.
186	    const topProjection = derivePresentation(writ, lookupConfig);
187	
188	    const result: WritShowResult = {
189	      ...writ,
190	      classification: topProjection.classification,
191	      allowedTransitions: topProjection.allowedTransitions,
192	      links,
193	      parent,
194	      children: { summary, items },
195	    };
196	
197	    if (params.format === 'json') {
198	      return result;
199	    }
200	
201	    return renderShow(result, topProjection.attrs);
202	  },
203	});
