            upstream: { g: { guildName: 'g', guildPath: '/p' } },
          }),
        ),
      /pollIntervalMs must be a positive number/,
    );
  });

  it('rejects malformed timeoutMs', async () => {
    await assert.rejects(
      () =>
        commissionPostXguildEngine.run(
